fn solve(n: i64, k: i64) -> i64 {
    if k == 0 {
        return 1;
    }

    const MAX: usize = 200;
    let mut depth = vec![-1; MAX + 1];
    depth[1] = 0;
    for x in 2..=MAX {
        let pop = (x as u32).count_ones() as usize;
        if pop <= MAX {
            depth[x] = depth[pop] + 1;
        }
    }

    let mut set_S = std::collections::HashSet::new();
    for x in 1..=MAX {
        if depth[x] == k - 1 {
            set_S.insert(x);
        }
    }

    let bin_str = format!("{:b}", n);
    let s: Vec<char> = bin_str.chars().collect();
    let m = s.len();
    let mut dp = vec![vec![vec![0; m + 1]; 2]; m + 1];
    dp[0][1][0] = 1;

    for i in 0..m {
        for tight in 0..2 {
            for count in 0..=m {
                let cur = dp[i][tight][count];
                if cur == 0 {
                    continue;
                }
                let tight_flag = tight == 1;
                let max_digit = if tight_flag { s[i] } else { '1' };
                for d in &['0', '1'] {
                    if *d > max_digit {
                        continue;
                    }
                    let new_tight = tight_flag && (*d == s[i]);
                    let new_tight_idx = new_tight as usize;
                    let new_count = if *d == '1' {
                        count + 1
                    } else {
                        count
                    };
                    if new_count <= m {
                        dp[i + 1][new_tight_idx][new_count] += cur;
                    }
                }
            }
        }
    }

    let mut total = 0;
    for tight in 0..2 {
        for count in 0..=m {
            if set_S.contains(&count) {
                total += dp[m][tight][count];
            }
        }
    }

    if k == 1 {
        if total > 0 {
            total - 1
        } else {
            0
        }
    } else {
        total
    }
}
